const cq = $input.first().json.callback_query;
if (!cq || !cq.data) throw new Error('no callback_query');
const i = cq.data.indexOf(':');
const pfx = cq.data.slice(0, i);
const run_id = cq.data.slice(i + 1);
const BRANDS = {
  'soulpaws-':      { brand: 'soulpaws_ai',    handle: '@soulpaws.ai',    ig_id: '47061', tt_id: '39894', subdir: 'soulpaws'       },
  'catauralove-':   { brand: 'cat_aura',       handle: '@cat_aura',       ig_id: '22251', tt_id: '22514', subdir: 'cat_aura'       },
  'loyalbondlove-': { brand: 'loyal_bond0',    handle: '@loyal_bond0',    ig_id: '44221', tt_id: '40322', subdir: 'loyal_bond0'    },
  'ariaaffirm-':    { brand: 'aria_frequency', handle: '@aria_frequency', ig_id: '44002', tt_id: '40115', subdir: 'aria_frequency' }
};
let brand_cfg = null;
for (const [prefix, cfg] of Object.entries(BRANDS)) {
  if (run_id.startsWith(prefix)) { brand_cfg = cfg; break; }
}
if (!brand_cfg) {
  return [];
}
const action = pfx === 'a' ? 'approve' : pfx === 'r' ? 'reject' : '';
if (!action) throw new Error('bad callback data: ' + cq.data);
return [{ json: { action, run_id, cq_id: cq.id, chat_id: cq.message.chat.id, message_id: cq.message.message_id, ...brand_cfg } }];

