parameters.jsCode:
const ctx = $('🧩 Parse Callback').first().json;
const raw = $('📄 Load Run Metadata').first().json.stdout || '{}';
let m = {};
try { m = JSON.parse(raw); } catch (e) { m = {}; }
const run = ctx.run_id;
const base = 'https://content.littlesouls.app/viral-pet-media/' + ctx.subdir + '/' + run;
const count = m.slide_count || 7;
const items = [];
for (let i = 1; i <= count; i++) {
  const n = i.toString().padStart(2, '0');
  items.push({ json: {
    run_id: run,
    brand: ctx.brand,
    handle: ctx.handle,
    ig_id: ctx.ig_id,
    tt_id: ctx.tt_id,
    subdir: ctx.subdir,
    slide_index: i,
    slide_url: base + '/slide_' + n + '.png',
    caption_ig: m.caption_ig || '',
    caption_tt: m.caption_tt || '',
    theme: m.theme || '',
    chat_id: ctx.chat_id,
    message_id: ctx.message_id,
    slide_count: count
  }});
}
return items;

const items = $input.all();
const urls = items.map(it => it.json.url).filter(Boolean);
if (urls.length === 0) throw new Error('no Blotato URLs aggregated');
const ctx = $('🧩 Parse Callback').first().json;
const meta = items[0].json;

// Random posting slot in the 08:00–21:00 UTC window, ≥ 20min from now.
// If too late today, roll to tomorrow's window. Each brand approval = its own
// random time, so the 3 daily posts scatter naturally across the day.
const now = Date.now();
const t = new Date();
const y = t.getUTCFullYear(), mo = t.getUTCMonth(), d = t.getUTCDate();
const winStart = Date.UTC(y, mo, d, 8, 0, 0);
const winEnd = Date.UTC(y, mo, d, 21, 0, 0);
const earliest = Math.max(now + 20 * 60 * 1000, winStart);
let sched;
if (earliest >= winEnd) {
  const tomStart = winStart + 24 * 3600 * 1000;
  sched = new Date(tomStart + Math.random() * (13 * 3600 * 1000));
} else {
  sched = new Date(earliest + Math.random() * (winEnd - earliest));
}
const sched_time = sched.toISOString();

return [{ json: {
  run_id: ctx.run_id,
  brand: ctx.brand,
  handle: ctx.handle,
  ig_id: ctx.ig_id,
  tt_id: ctx.tt_id,
  chat_id: ctx.chat_id,
  message_id: ctx.message_id,
  caption_ig: meta.caption_ig || '',
  caption_tt: meta.caption_tt || '',
  theme: meta.theme || '',
  media_urls: urls,
  slide_count: urls.length,
  sched_time
} }];

